import re

def count_politicians(articles, politician_names):
    # Create a set of lowercase politician names for case-insensitive matching
    lowercase_politicians = {name.lower() for name in politician_names}

    # Initialize a dictionary to hold counts
    counts = {}

    # Process each article
    for article in articles:
        # Extract all names from the article using a regex pattern
        names = re.findall(r'\b(?:\w+\s+\w+)+\b', article)

        # Convert names to lowercase and check against the set of politicians
        for name in names:
            lower_name = name.lower()
            if lower_name in lowercase_politicians:
                counts[lower_name] = counts.get(lower_name, 0) + 1

    return counts
